// ── SEARCH ───────────────────────────────────────────────────
function searchMonsters(query) {
  if (!query || !query.trim()) return MONSTER_DB.slice(0, 20);
  const q = query.toLowerCase().trim();
  return MONSTER_DB.filter(m =>
    m.name.toLowerCase().includes(q) ||
    m.meta.toLowerCase().includes(q) ||
    m.cr === q
  ).slice(0, 30);
}

// ── ENCOUNTER MANAGEMENT ─────────────────────────────────────

function addMonsterToEncounter(templateName) {
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return null;
  const template = MONSTER_DB.find(x => x.name === templateName);
  if (!template) return null;

  m.monsters = m.monsters || [];
  const count = m.monsters.filter(x => x.templateName === templateName).length;
  const instance = {
    id: Date.now().toString(36) + Math.random().toString(36).slice(2),
    templateName: template.name,
    displayName: count > 0 ? template.name + ' ' + (count + 1) : template.name,
    ac: template.ac,
    maxHp: template.hp,
    currentHp: template.hp,
    cr: template.cr,
    meta: template.meta,
    imgUrl: template.imgUrl
  };

  m.monsters.push(instance);
  m.updatedAt = Date.now();
  saveCurrentMap();
  return instance;
}

function removeMonsterFromEncounter(monsterId) {
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return;
  m.monsters = (m.monsters || []).filter(x => x.id !== monsterId);
  m.tokens = (m.tokens || []).filter(t => t.monsterId !== monsterId);
  m.updatedAt = Date.now();
  saveCurrentMap();
  renderTokensOnMap();
  renderMonsterSidebar();
}

function updateMonsterHp(monsterId, delta) {
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return;
  const mon = (m.monsters || []).find(x => x.id === monsterId);
  if (!mon) return;
  const oldHp = mon.currentHp;
  mon.currentHp = Math.max(0, Math.min(mon.maxHp, mon.currentHp + delta));
  if (typeof logHpChange === 'function') logHpChange(mon.id, mon.displayName || mon.templateName, 'monster', oldHp, mon.currentHp);
  m.updatedAt = Date.now();
  saveCurrentMap();
  renderTokensOnMap();
  renderMonsterSidebar();
  // Re-render popup content and reposition to new token element
  renderMonsterPopup(monsterId);
  repositionMonsterPopup(monsterId);
}

function setMonsterHp(monsterId, val) {
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return;
  const mon = (m.monsters || []).find(x => x.id === monsterId);
  if (!mon) return;
  const oldHp = mon.currentHp;
  mon.currentHp = Math.max(0, Math.min(mon.maxHp, parseInt(val) || 0));
  if (typeof logHpChange === 'function') logHpChange(mon.id, mon.displayName || mon.templateName, 'monster', oldHp, mon.currentHp);
  m.updatedAt = Date.now();
  saveCurrentMap();
  renderTokensOnMap();
}

// ── SIDEBAR RENDERING ────────────────────────────────────────
let _monsterSearchTimeout = null;

function onMonsterSearch(e) {
  clearTimeout(_monsterSearchTimeout);
  _monsterSearchTimeout = setTimeout(() => {
    renderMonsterSearchResults(e.target.value);
  }, 150);
}

function renderMonsterSearchResults(query) {
  const el = document.getElementById('monster-search-results');
  if (!el) return;
  const results = searchMonsters(query);
  if (!results.length) {
    el.innerHTML = '<div style="font-size:.7rem;color:var(--text4);padding:.3rem 0;">No matches</div>';
    return;
  }
  el.innerHTML = results.map(m => {
    const safeName = m.name.replace(/'/g, "\\'");
    return '<div class="sidebar-char-item" onclick="pickMonsterForPlacement(\'' + safeName + '\')" title="' + m.meta + '" style="padding:8px;gap:10px;">' +
      '<div style="width:32px;height:32px;border-radius:50%;background:#3a1818;border:2px solid #8a2020;display:flex;align-items:center;justify-content:center;flex-shrink:0;">' +
        '<span style="font-size:.6rem;font-weight:700;color:#c04040;font-family:var(--font-mono);">' + m.cr + '</span>' +
      '</div>' +
      '<div style="min-width:0;flex:1;">' +
        '<div style="font-size:.78rem;color:#e2dbd0;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + m.name + '</div>' +
        '<div style="display:flex;gap:8px;font-size:.62rem;margin-top:2px;">' +
          '<span style="color:#c04040;">\u2764 ' + m.hp + '</span>' +
          '<span style="color:#c8b070;">\u26e8 ' + m.ac + '</span>' +
          '<span style="color:#7a7268;">' + m.meta.split(',')[0] + '</span>' +
        '</div>' +
      '</div>' +
    '</div>';
  }).join('');
}

function renderMonsterSidebar() {
  const m = maps.find(x => x.id === currentMapId);
  const el = document.getElementById('monster-encounter-list');
  if (!el) return;
  const monsters = m?.monsters || [];
  if (!monsters.length) {
    el.innerHTML = '<div style="font-size:.65rem;color:var(--text4);padding:.2rem 0;">No monsters in encounter</div>';
    return;
  }
  el.innerHTML = monsters.map(mon => {
    const pct = Math.round((mon.currentHp / mon.maxHp) * 100);
    const hpCol = pct > 60 ? '#4a9a40' : pct > 25 ? '#b8902a' : '#a03030';
    const isDead = mon.currentHp <= 0;
    return '<div class="sidebar-char-item" id="msi-' + mon.id + '" onclick="selectMonsterForPlace(\'' + mon.id + '\')" title="Click to place token" style="padding:8px;gap:8px;' + (isDead ? 'opacity:.4;' : '') + '">' +
      '<div style="min-width:0;flex:1;">' +
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px;">' +
          '<span style="font-size:.78rem;color:' + (isDead ? '#504840' : '#e2dbd0') + ';font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;' + (isDead ? 'text-decoration:line-through;' : '') + '">' + mon.displayName + '</span>' +
          '<span style="font-size:.58rem;color:#c8b070;flex-shrink:0;margin-left:4px;">\u26e8 ' + mon.ac + '</span>' +
        '</div>' +
        '<div style="display:flex;align-items:center;gap:4px;margin-top:2px;">' +
          '<button onclick="event.stopPropagation();updateMonsterHp(\'' + mon.id + '\',-1)" style="width:18px;height:18px;border-radius:4px;border:1px solid #3a3020;background:#1e1810;color:#b0a898;cursor:pointer;font-size:.7rem;display:flex;align-items:center;justify-content:center;font-family:var(--font-mono);">-</button>' +
          '<div style="flex:1;height:5px;background:#1e1810;border-radius:3px;overflow:hidden;">' +
            '<div style="width:' + pct + '%;height:100%;background:' + hpCol + ';border-radius:3px;transition:width .3s;"></div>' +
          '</div>' +
          '<span style="font-size:.6rem;color:' + hpCol + ';font-family:var(--font-mono);white-space:nowrap;min-width:42px;text-align:center;">' + mon.currentHp + '/' + mon.maxHp + '</span>' +
          '<button onclick="event.stopPropagation();updateMonsterHp(\'' + mon.id + '\',1)" style="width:18px;height:18px;border-radius:4px;border:1px solid #3a3020;background:#1e1810;color:#b0a898;cursor:pointer;font-size:.7rem;display:flex;align-items:center;justify-content:center;font-family:var(--font-mono);">+</button>' +
        '</div>' +
      '</div>' +
      '<button style="padding:2px 4px;font-size:.55rem;background:none;border:none;cursor:pointer;color:#6a3030;flex-shrink:0;" onclick="event.stopPropagation();removeMonsterFromEncounter(\'' + mon.id + '\')">\u2715</button>' +
    '</div>';
  }).join('');
}

// ── MONSTER PLACEMENT ────────────────────────────────────────
let placingMonsterId = null;

function pickMonsterForPlacement(templateName) {
  const instance = addMonsterToEncounter(templateName);
  if (!instance) return;
  renderMonsterSidebar();
  selectMonsterForPlace(instance.id);
}

function selectMonsterForPlace(monsterId) {
  if (placingMonsterId === monsterId) { clearMonsterPlacing(); return; }
  if (typeof setPlacingMode === 'function') setPlacingMode(null);
  placingMonsterId = monsterId;

  document.querySelectorAll('.sidebar-char-item').forEach(el => el.classList.remove('placing'));
  const el = document.getElementById('msi-' + monsterId);
  if (el) el.classList.add('placing');

  const stage = document.getElementById('map-stage');
  const hint = document.getElementById('place-hint');
  if (stage) stage.style.cursor = 'crosshair';
  if (hint) hint.style.display = 'flex';
}

function clearMonsterPlacing() {
  placingMonsterId = null;
  document.querySelectorAll('.sidebar-char-item').forEach(el => el.classList.remove('placing'));
  const stage = document.getElementById('map-stage');
  const hint = document.getElementById('place-hint');
  if (stage) stage.style.cursor = '';
  if (hint) hint.style.display = 'none';
}

// ── MONSTER HP POPUP ─────────────────────────────────────────
let _monsterPopupId = null;

function showMonsterPopup(monsterId, tokenEl) {
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return;
  if (m.fog?.viewMode === 'player') return;
  const mon = (m.monsters || []).find(x => x.id === monsterId);
  if (!mon) return;

  _monsterPopupId = monsterId;
  renderMonsterPopup(monsterId);

  const popup = document.getElementById('monster-popup');
  if (!popup || !tokenEl) return;
  popup.style.display = 'block';

  const tokRect = tokenEl.getBoundingClientRect();
  const stageWrap = document.querySelector('.map-stage-wrap');
  if (stageWrap) {
    const wrapRect = stageWrap.getBoundingClientRect();
    popup.style.left = (tokRect.right - wrapRect.left + stageWrap.scrollLeft + 8) + 'px';
    popup.style.top = (tokRect.top - wrapRect.top + stageWrap.scrollTop) + 'px';
  }
}

function renderMonsterPopup(monsterId) {
  const m = maps.find(x => x.id === currentMapId);
  const mon = (m?.monsters || []).find(x => x.id === monsterId);
  const popup = document.getElementById('monster-popup');
  if (!popup || !mon || _monsterPopupId !== monsterId) return;

  const pct = Math.round((mon.currentHp / mon.maxHp) * 100);
  const col = pct > 60 ? '#4a9a40' : pct > 25 ? '#b8902a' : '#8a2020';
  popup.innerHTML =
    '<div style="font-size:.78rem;font-family:var(--font-display);color:#e2dbd0;margin-bottom:4px;">' + mon.displayName + '</div>' +
    '<div style="font-size:.62rem;color:#7a7268;margin-bottom:6px;">' + mon.meta + ' \u00b7 CR ' + mon.cr + '</div>' +
    '<div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;">' +
      '<button class="btn btn-sm" style="padding:0 6px;font-size:.75rem;background:#362c22;border-color:#3a3428;color:#b0a898;" onclick="updateMonsterHp(\'' + mon.id + '\',-5)">-5</button>' +
      '<button class="btn btn-sm" style="padding:0 6px;font-size:.75rem;background:#362c22;border-color:#3a3428;color:#b0a898;" onclick="updateMonsterHp(\'' + mon.id + '\',-1)">-</button>' +
      '<div style="text-align:center;">' +
        '<input type="number" value="' + mon.currentHp + '" min="0" max="' + mon.maxHp + '" style="width:50px;text-align:center;font-size:.85rem;font-weight:600;background:#1e1810;border:1px solid #3a3428;border-radius:6px;color:#e2dbd0;padding:3px;" onchange="setMonsterHp(\'' + mon.id + '\',this.value)">' +
        '<div style="font-size:.55rem;color:#7a7268;">/ ' + mon.maxHp + ' HP</div>' +
      '</div>' +
      '<button class="btn btn-sm" style="padding:0 6px;font-size:.75rem;background:#362c22;border-color:#3a3428;color:#b0a898;" onclick="updateMonsterHp(\'' + mon.id + '\',1)">+</button>' +
      '<button class="btn btn-sm" style="padding:0 6px;font-size:.75rem;background:#362c22;border-color:#3a3428;color:#b0a898;" onclick="updateMonsterHp(\'' + mon.id + '\',5)">+5</button>' +
      '<div style="font-size:.65rem;color:#c8b070;margin-left:4px;">AC ' + mon.ac + '</div>' +
    '</div>' +
    '<div style="height:5px;background:#1e1810;border-radius:3px;overflow:hidden;">' +
      '<div style="width:' + pct + '%;height:100%;background:' + col + ';border-radius:3px;transition:width .2s;"></div>' +
    '</div>';
}

function repositionMonsterPopup(monsterId) {
  const popup = document.getElementById('monster-popup');
  if (!popup || popup.style.display === 'none') return;
  // Find the token for this monster
  const m = maps.find(x => x.id === currentMapId);
  if (!m) return;
  const tok = (m.tokens || []).find(t => t.monsterId === monsterId);
  if (!tok) return;
  const tokenEl = document.getElementById('tok-' + tok.id);
  if (!tokenEl) return;
  const tokRect = tokenEl.getBoundingClientRect();
  const stageWrap = document.querySelector('.map-stage-wrap');
  if (stageWrap) {
    const wrapRect = stageWrap.getBoundingClientRect();
    popup.style.left = (tokRect.right - wrapRect.left + stageWrap.scrollLeft + 8) + 'px';
    popup.style.top = (tokRect.top - wrapRect.top + stageWrap.scrollTop) + 'px';
  }
}

function hideMonsterPopup() {
  _monsterPopupId = null;
  const popup = document.getElementById('monster-popup');
  if (popup) { popup.style.display = 'none'; popup.innerHTML = ''; }
}
